using Microsoft.Extensions.AI;
using OpenAI;
using System.ComponentModel;
using System.Text.Json;

Console.WriteLine("Research Agent Starting...");

// Configure the chat client with tool support
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Note-taking state
var notes = new List<string>();

// Define tools
var searchTool = AIFunctionFactory.Create(
    [Description("Search the web for information on a query. Returns relevant snippets.")]
    (string query) =>
    {
        Console.WriteLine($"  [Tool] Searching web for: {query}");
        // Simulated web search results for demonstration
        var results = query.ToLowerInvariant() switch
        {
            var q when q.Contains("quantum computing") => new[]
            {
                "Quantum computing uses qubits that can exist in superposition, enabling parallel computation.",
                "Google's Willow chip (2024) achieved quantum error correction below threshold for the first time.",
                "IBM plans to deliver a 100,000-qubit system by 2033.",
                "Quantum computers threaten current encryption but enable new drug discovery and optimization solutions."
            },
            var q when q.Contains("application") || q.Contains("use case") => new[]
            {
                "Key applications: cryptography, drug discovery, financial modeling, supply chain optimization.",
                "Quantum machine learning could exponentially speed up training of AI models.",
                "Material science simulations on quantum hardware could revolutionize battery and solar cell design."
            },
            var q when q.Contains("challenge") || q.Contains("limitation") => new[]
            {
                "Decoherence and noise remain the biggest engineering challenges.",
                "Current quantum computers require near absolute-zero temperatures.",
                "Error rates are still too high for most practical applications without error correction.",
                "Scaling beyond a few thousand qubits is an unsolved engineering problem."
            },
            _ => new[]
            {
                $"Search results for '{query}': Multiple sources discuss recent advances and ongoing research.",
                "Experts predict significant breakthroughs in the next 5-10 years.",
                "Both academic and industry labs are investing heavily in this area."
            }
        };
        return string.Join("\n", results);
    },
    "web_search");

var notetool = AIFunctionFactory.Create(
    [Description("Save a research note. Use this to record key findings during research.")]
    (string note) =>
    {
        Console.WriteLine($"  [Tool] Saving note: {note[..Math.Min(note.Length, 80)]}...");
        notes.Add(note);
        return $"Note saved. Total notes: {notes.Count}";
    },
    "take_note");

var getNotesTool = AIFunctionFactory.Create(
    [Description("Retrieve all saved research notes to help write a summary.")]
    () =>
    {
        Console.WriteLine("  [Tool] Retrieving all notes...");
        return notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n---\n", notes.Select((n, i) => $"Note {i + 1}: {n}"));
    },
    "get_notes");

// Set up the conversation
var topic = args.Length > 0 ? string.Join(" ", args) : "quantum computing";
Console.WriteLine($"Researching topic: {topic}\n");

var chatOptions = new ChatOptions
{
    Tools = [searchTool, noteTool, getNotesTool]
};

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research a given topic thoroughly by:
        1. Searching the web for information (use multiple searches with different angles)
        2. Taking notes on key findings
        3. Retrieving your notes and producing a well-structured summary

        Always search at least 2-3 different aspects of the topic, take notes on important
        findings, then retrieve your notes and write a final summary.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}")
};

// Agent loop
Console.WriteLine("Agent is researching...\n");

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n========== RESEARCH SUMMARY ==========\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n=======================================");
Console.WriteLine($"\nResearch complete. {notes.Count} notes were taken during the process.");

